// // This module decrements its count value on each rising edge of the clock signal. When the reset signal is asserted, the counter resets to zero. Additionally, when the counter reaches its minimum value of 0, it wraps around to 15, ensuring continuous count cycling.
module top_module(clk, reset, count);input clk, reset;
  output reg [3:0] count;

  always @(posedge clk or posedge reset) begin
    if (reset) begin
      count <= 4'b0;
    end else if (count == 4'b1111) begin
      count <= 4'b0;
    end else begin
      count <= count + 1;
    end
  end
endmodule
